use std::collections::VecDeque;

struct MessageQueue {
    buffer: VecDeque<String>,
    capacity: usize,
}

impl MessageQueue {
    fn new(capacity: usize) -> Self {
        MessageQueue {
            buffer: VecDeque::with_capacity(capacity),
            capacity,
        }
    }

    fn enqueue(&mut self, message: String) -> Result<(), &'static str> {
        if self.buffer.len() >= self.capacity {
            return Err("Queue is full");
        }
        self.buffer.push_back(message);
        Ok(())
    }

    fn dequeue(&mut self) -> Option<String> {
        self.buffer.pop_front()
    }

    fn size(&self) -> usize {
        self.buffer.len()
    }
}

use std::collections::VecDeque;
use std::sync::Mutex;

struct KeyBuffer {
    buffer: Mutex<VecDeque<u64>>
}

impl KeyBuffer {
    fn new() -> Self {
        KeyBuffer { 
            buffer: Mutex::new(VecDeque::new()) 
        }
    }

    fn add_key(&self, key: u64) {
        let mut guard = self.buffer.lock().unwrap();
        guard.push_back(key);
    }

    fn process_next_key(&self) -> Option<u64> {
        let mut guard = self.buffer.lock().unwrap();
        if let Some(key) = guard.pop_front() {
            Some(key)
        } else {
            None
        }
    }
}

fn main() {
    let buffer = KeyBuffer::new();
    buffer.add_key(1024);
    buffer.add_key(2048);

    let key1 = buffer.process_next_key();
    println!("Processed key 1: {}", key1.unwrap());

    buffer.add_key(3072);

    let key2 = buffer.process_next_key();
    println!("Processed key 2: {}", key2.unwrap());

    let key3 = buffer.process_next_key();
    if key3.is_none() {
        println!("Buffer is empty.");
    }
}

use std::collections::VecDeque;

struct BurnDownTracker {
    history: VecDeque<u32>,
    capacity: usize,
}

impl BurnDownTracker {
    fn new(capacity: usize) -> Self {
        BurnDownTracker {
            history: VecDeque::with_capacity(capacity),
            capacity,
        }
    }

    fn add_step(&mut self, value: u32) {
        if self.history.len() >= self.capacity {
            self.history.pop_front();
        }
        self.history.push_back(value);
    }

    fn get_current_data(&self) -> &VecDeque<u32> {
        &self.history
    }

    fn print_summary(&self) {
        let mut min_val = u32::MAX;
        let mut max_val = 0;
        for &val in self.get_current_data() {
            if val < min_val { min_val = val; }
            if val > max_val { max_val = val; }
        }
        println!("--- Burn Down Summary ---");
        println!("Stored steps count: {}", self.history.len());
        println!("Minimum progress recorded: {}", min_val);
        println!("Maximum progress recorded: {}", max_val);
    }
}

fn main() {
    let mut tracker = BurnDownTracker::new(5);

    tracker.add_step(100);
    tracker.print_summary();

    tracker.add_step(80);
    tracker.add_step(60);
    tracker.print_summary();

    tracker.add_step(40); // Window is now full (100, 80, 60, 40)
    tracker.print_summary();

    tracker.add_step(20); // Should push out the original 100
    println!("nAdded step 20, simulating window shift.");
    tracker.print_summary();

    tracker.add_step(5);
    tracker.print_summary();
}

use std::collections::VecDeque;

struct ParticleSystem {
    history: VecDeque<(f32, f32)>, 
    capacity: usize,
}

impl ParticleSystem {
    fn new(capacity: usize) -> Self {
        ParticleSystem {
            history: VecDeque::with_capacity(capacity),
            capacity,
        }
    }

    fn add_position(&mut self, x: f32, y: f32) {
        let new_pos = (x, y);
        self.history.push_back(new_pos);

        if self.history.len() > self.capacity {
            self.history.pop_front();
        }
    }

    fn get_last_positions(&self) -> &VecDeque<(f32, f32)> {
        &self.history
    }
}

fn main() {
    let mut emitter = ParticleSystem::new(10);
    emitter.add_position(1.0, 2.0);
    emitter.add_position(1.5, 2.1);
    emitter.add_position(2.0, 2.3);

    println!("Particle history length: {}", emitter.get_last_positions().len());

    let current_history = emitter.get_last_positions();
    if let Some(&(x, y)) = current_history.back() {
        println!("Most recent position recorded at: ({}, {} )", x, y);
    }
}

use std::collections::VecDeque;

fn main() {
    let mut buffer: VecDeque<i32> = VecDeque::new();
    buffer.push_back(10);
    buffer.push_front(5);
    println!("Initial buffer size: {}", buffer.len());

    buffer.pop_back();
    buffer.pop_front();

    let item = buffer.pop_back();
    if let Some(val) = item {
        println!("Popped back successfully: {}", val);
    }

    buffer.push_back(20);
    buffer.push_front(1);
    println!("Final buffer size: {}", buffer.len());
}
